class CircularQueue {
  int[] arr; int front = 0, rear = -1, size = 0, capacity;
  CircularQueue(int cap){ capacity = cap; arr = new int[cap]; }
  void enqueue(int x){
    if(size == capacity) return;
    rear = (rear + 1) % capacity;
    arr[rear] = x; size++;
  }
  int dequeue(){
    int val = arr[front];
    front = (front + 1) % capacity; size--;
    return val;
  }
}

int shortestPath(Map<Integer,List<Integer>> graph, int start, int target){
  Queue<Integer> queue = new LinkedList<>();
  Map<Integer,Integer> dist = new HashMap<>();
  queue.add(start); dist.put(start, 0);
  while(!queue.isEmpty()){
    int node = queue.poll();
    if(node == target) return dist.get(node);
    for(int neighbor : graph.getOrDefault(node, new ArrayList<>())){
      if(!dist.containsKey(neighbor)){
        dist.put(neighbor, dist.get(node) + 1);
        queue.add(neighbor);
      }
    }
  }
  return -1;
}

