int romanToInt(String s){
  Map<Character,Integer> vals = Map.of('I',1,'V',5,'X',10,'L',50,'C',100,'D',500,'M',1000);
  int total = 0;
  for(int i = 0; i < s.length(); i++){
    int curr = vals.get(s.charAt(i));
    int next = (i+1 < s.length()) ? vals.get(s.charAt(i+1)) : 0;
    total += (curr < next) ? -curr : curr;
  }
  return total;
}

