boolean isSafe(int[] cols, int row, int col){
  for(int r = 0; r < row; r++){
    if(cols[r] == col || Math.abs(cols[r]-col) == row-r) return false;
  }
  return true;
}

void flatten(Object item, List<Integer> result){
  if(item instanceof List){
    for(Object sub : (List<?>) item) flatten(sub, result);
  } else {
    result.add((Integer) item);
  }
}

int[] nextGreaterElement(int[] arr){
  int[] result = new int[arr.length];
  Deque<Integer> stack = new ArrayDeque<>();
  for(int i = arr.length-1; i >= 0; i--){
    while(!stack.isEmpty() && stack.peek() <= arr[i]) stack.pop();
    result[i] = stack.isEmpty() ? -1 : stack.peek();
    stack.push(arr[i]);
  }
  return result;
}

class LRUCache extends LinkedHashMap<Integer,Integer> {
  private int capacity;
  LRUCache(int capacity){
    super(capacity, 0.75f, true);
    this.capacity = capacity;
  }
  protected boolean removeEldestEntry(Map.Entry<Integer,Integer> eldest){
    return size() > capacity;
  }
}

boolean wordBreak(String s, Set<String> dict){
  boolean[] dp = new boolean[s.length()+1];
  dp[0] = true;
  for(int i = 1; i <= s.length(); i++){
    for(int j = 0; j < i; j++){
      if(dp[j] && dict.contains(s.substring(j, i))){
        dp[i] = true; break;
      }
    }
  }
  return dp[s.length()];
}

void quickSort(int[] arr, int low, int high){
  if(low < high){
    int pi = partition(arr, low, high);
    quickSort(arr, low, pi-1);
    quickSort(arr, pi+1, high);
  }
}
int partition(int[] arr, int low, int high){
  int pivot = arr[high], i = low-1;
  for(int j=low;j<high;j++){
    if(arr[j] < pivot){
      i++;
      int t=arr[i]; arr[i]=arr[j]; arr[j]=t;
    }
  }
  int t=arr[i+1]; arr[i+1]=arr[high]; arr[high]=t;
  return i+1;
}

void mergeSort(int[] arr, int l, int r){
  if(l < r){
    int m = (l+r)/2;
    mergeSort(arr, l, m);
    mergeSort(arr, m+1, r);
    merge(arr, l, m, r);
  }
}

int kthLargest(int[] arr, int k){
  Integer[] boxed = Arrays.stream(arr).boxed().toArray(Integer[]::new);
  Arrays.sort(boxed, Collections.reverseOrder());
  return boxed[k-1];
}

