}

void permute(char[] arr, int k){
  if(k == arr.length-1){
    System.out.println(new String(arr));
    return;
  }
  for(int i=k;i<arr.length;i++){
    char t=arr[k]; arr[k]=arr[i]; arr[i]=t;
    permute(arr, k+1);
    t=arr[k]; arr[k]=arr[i]; arr[i]=t;
  }
}

