int equilibriumIndex(int[] arr){
  int total = Arrays.stream(arr).sum(), leftSum = 0;
  for(int i=0;i<arr.length;i++){
    total -= arr[i];
    if(leftSum == total) return i;
    leftSum += arr[i];
  }
  return -1;
}

void moveZeros(int[] arr){
  int insertPos = 0;
  for(int x : arr) if(x != 0) arr[insertPos++] = x;
  while(insertPos < arr.length) arr[insertPos++] = 0;
}

int majorityElement(int[] arr){
  int count = 0, candidate = 0;
  for(int x : arr){
    if(count == 0) candidate = x;
    count += (x == candidate) ? 1 : -1;
  }
  return candidate;
}

boolean hasUniqueChars(String s){
  Set<Character> seen = new HashSet<>();
  for(char c : s.toCharArray()){
    if(!seen.add(c)) return false;
  }
  return true;
}

int climbStairs(int n){
  if(n <= 2) return n;
  int a=1, b=2;
  for(int i=3;i<=n;i++){
    int c = a+b; a=b; b=c;
  }
  return b;
}
